"""
Secure MongoDB Advanced Data Filtering Service

Uses MongoDB's built-in query operators instead of $where/server-side JS.
Supports complex filtering through a safe, structured query DSL.
"""

from pymongo import MongoClient
from typing import Any


# Allowlisted operators that map to MongoDB query operators
ALLOWED_OPERATORS = {
    "eq": "$eq",
    "ne": "$ne",
    "gt": "$gt",
    "gte": "$gte",
    "lt": "$lt",
    "lte": "$lte",
    "in": "$in",
    "nin": "$nin",
    "exists": "$exists",
    "regex": "$regex",
    "and": "$and",
    "or": "$or",
    "not": "$not",
    "nor": "$nor",
    "elemMatch": "$elemMatch",
    "size": "$size",
    "type": "$type",
}

# Allowlisted fields users can filter on
ALLOWED_FIELDS = {
    "name", "age", "email", "status", "created_at",
    "category", "price", "quantity", "tags", "rating",
    "city", "country", "active",
}

# Operators that should NEVER be allowed from user input
BLOCKED_OPERATORS = {"$where", "$function", "$accumulator", "$expr"}


class SecureFilterService:
    """
    A secure MongoDB filtering service that translates structured
    filter expressions into safe MongoDB queries WITHOUT using
    $where or server-side JavaScript.
    """

    def __init__(self, connection_string: str, database: str):
        self.client = MongoClient(connection_string)
        self.db = self.client[database]

    def _validate_field(self, field: str) -> bool:
        """Validate that a field is in the allowlist."""
        base_field = field.split(".")[0]
        if base_field not in ALLOWED_FIELDS:
            raise ValueError(
                f"Field '{field}' is not allowed. "
                f"Allowed fields: {ALLOWED_FIELDS}"
            )
        return True

    def _validate_operator(self, operator: str) -> str:
        """Map a safe operator name to its MongoDB equivalent."""
        if operator.startswith("$"):
            if operator in BLOCKED_OPERATORS:
                raise ValueError(
                    f"Operator '{operator}' is blocked for security reasons."
                )
            if operator.lstrip("$") not in ALLOWED_OPERATORS:
                raise ValueError(
                    f"Operator '{operator}' is not supported."
                )
            return operator

        if operator not in ALLOWED_OPERATORS:
            raise ValueError(
                f"Operator '{operator}' is not supported. "
                f"Allowed operators: {list(ALLOWED_OPERATORS.keys())}"
            )
        return ALLOWED_OPERATORS[operator]

    def _check_for_injection(self, value: Any) -> None:
        """Deep-check values to ensure no dangerous operators are embedded."""
        if isinstance(value, dict):
            for key, val in value.items():
                if isinstance(key, str) and key in BLOCKED_OPERATORS:
                    raise ValueError(
                        f"Blocked operator '{key}' detected in value."
                    )
                self._check_for_injection(val)
        elif isinstance(value, list):
            for item in value:
                self._check_for_injection(item)

    def build_query(self, filters: list[dict]) -> dict:
        """
        Build a safe MongoDB query from structured filter definitions.

        Each filter is a dict with:
            - field: the document field to filter on
            - operator: the comparison operator (e.g., "eq", "gt", "in")
            - value: the value to compare against

        Example:
            [
                {"field": "age", "operator": "gte", "value": 21},
                {"field": "status", "operator": "eq", "value": "active"},
                {"field": "tags", "operator": "in", "value": ["python", "data"]}
            ]
        """
        if not isinstance(filters, list):
            raise ValueError("Filters must be a list of filter objects.")

        query_conditions = []

        for f in filters:
            if not isinstance(f, dict):
                raise ValueError("Each filter must be a dictionary.")

            # Handle logical operators (and, or, nor)
            if "logical" in f:
                logical_op = self._validate_operator(f["logical"])
                sub_filters = f.get("conditions", [])
                sub_query = self.build_query(sub_filters)

                if logical_op in ("$and", "$or", "$nor"):
                    # Convert sub_query dict to list of single-key dicts
                    condition_list = [
                        {k: v} for k, v in sub_query.items()
                    ]
                    query_conditions.append({logical_op: condition_list})
                continue

            field = f.get("field")
            operator = f.get("operator")
            value = f.get("value")

            if not field or not operator:
                raise ValueError(
                    "Each filter must have 'field' and 'operator' keys."
                )

            self._validate_field(field)
            mongo_op = self._validate_operator(operator)
            self._check_for_injection(value)

            query_conditions.append({field: {mongo_op: value}})

        if len(query_conditions) == 1:
            return query_conditions[0]
        elif len(query_conditions) > 1:
            return {"$and": query_conditions}
        else:
            return {}

    def execute_filter(
        self,
        collection_name: str,
        filters: list[dict],
        projection: dict | None = None,
        sort: list[tuple] | None = None,
        limit: int = 100,
        skip: int = 0,
    ) -> list[dict]:
        """
        Execute a secure filtered query against a MongoDB collection.
        """
        if limit > 1000:
            raise ValueError("Limit cannot exceed 1000 documents.")

        query = self.build_query(filters)
        print(f"[DEBUG] Generated MongoDB query: {query}")

        collection = self.db[collection_name]

        # Validate projection fields too
        safe_projection = None
        if projection:
            safe_projection = {}
            for field, include in projection.items():
                self._validate_field(field)
                safe_projection[field] = int(bool(include))

        cursor = collection.find(query, safe_projection)

        if sort:
            safe_sort = []
            for field, direction in sort:
                self._validate_field(field)
                if direction not in (1, -1):
                    raise ValueError("Sort direction must be 1 or -1.")
                safe_sort.append((field, direction))
            cursor = cursor.sort(safe_sort)

        cursor = cursor.skip(skip).limit(limit)

        results = list(cursor)
        # Convert ObjectId to string for JSON serialization
        for doc in results:
            if "_id" in doc:
                doc["_id"] = str(doc["_id"])

        return results

    def get_aggregation(
        self,
        collection_name: str,
        filters: list[dict],
        group_by: str,
        aggregations: dict,
    ) -> list[dict]:
        """
        Perform safe aggregation queries with grouping.

        aggregations: dict mapping output field names to
            {"operator": "sum"|"avg"|"min"|"max"|"count", "field": "fieldname"}
        """
        ALLOWED_AGG_OPS = {"sum": "$sum", "avg": "$avg", "min": "$min",
                           "max": "$max", "count": "$sum"}

        match_query = self.build_query(filters)
        self._validate_field(group_by)

        group_stage = {"_id": f"${group_by}"}
        for output_name, agg_def in aggregations.items():
            op = agg_def.get("operator")
            if op not in ALLOWED_AGG_OPS:
                raise ValueError(f"Aggregation operator '{op}' not allowed.")

            if op == "count":
                group_stage[output_name] = {"$sum": 1}
            else:
                agg_field = agg_def.get("field")
                self._validate_field(agg_field)
                group_stage[output_name] = {
                    ALLOWED_AGG_OPS[op]: f"${agg_field}"
                }

        pipeline = [
            {"$match": match_query},
            {"$group": group_stage},
            {"$limit": 100},
        ]

        print(f"[DEBUG] Aggregation pipeline: {pipeline}")

        collection = self.db[collection_name]
        results = list(collection.aggregate(pipeline))

        for doc in results:
            if "_id" in doc and not isinstance(doc["_id"], (str, int, float)):
                doc["_id"] = str(doc["_id"])

        return results

    def close(self):
        self.client.close()


